-- ---------------------------------------------------------- Tabel structuur voor tabel alg_drinks-- --------------------------------------------------------DROP TABLE IF EXISTS alg_drinks;CREATE TABLE IF NOT EXISTS alg_drinks (id smallint(6) NOT NULL default '0',naam varchar(20) NOT NULL default '',percent decimal(10,0) NOT NULL default '0',cc decimal(10,0) NOT NULL default '0',alccc decimal(10,0) NOT NULL default '0',factor decimal(10,0) NOT NULL default '0',notes varchar(70) NOT NULL default '') TYPE=MyISAM;-- Gegevens worden uitgevoerd voor tabel alg_drinks